            return cost
        }

        if steps > k {
            continue
        }

        // Regular move: right or down
        if col + 1 < n {
            let newCost = cost + grid[row][col + 1]
            if newCost < dist[row][col + 1] {
                dist[row][col + 1] = newCost
                pq.insert((row: row, col: col + 1, cost: newCost, steps: steps))
            }
        }

        if row + 1 < m {
            let newCost = cost + grid[row + 1][col]
            if newCost < dist[row + 1][col] {
                dist[row + 1][col] = newCost
                pq.insert((row: row + 1, col: col, cost: newCost, steps: steps))
            }
        }

        // Teleport: find all cells with value <= current cell's value
        for i in 0..<m {
            for j in 0..<n {
                if grid[i][j] <= grid[row][col] && dist[i][j] > cost {
