}

struct PriorityQueue<T: Comparable> {
    private var elements: [(T, Int64)] = []

    mutating func insert(_ value: T) {
        elements.append((value, Int64(elements.count)))
        var parent = elements.count - 1
        while parent > 0 {
            let parentIndex = (parent - 1) / 2
            if elements[parentIndex].0 <= value {
                break
            }
            elements.swapAt(parent, parentIndex)
            parent = parentIndex
        }
    }

    mutating func remove() -> T {
        guard !elements.isEmpty else { return T.min }
        let value = elements[0].0
        elements[0] = elements.last!
        elements.popLast()
        var index = 0
        while true {
            let left = 2 * index + 1
            let right = 2 * index + 2
            var smallest = index
            if left < elements.count && elements[left].0 < elements[smallest].0 {
                smallest = left
            }
            if right < elements.count && elements[right].0 < elements[smallest].0 {
                smallest = right
            }
            if smallest == index { break }
            elements.swapAt(index, smallest)
            index = smallest
        }
        return value
    }
}
